import React, { useState } from "react";
import "./BloodBankPage.css";

const BloodBankPage = () => {
  const [centers] = useState([
    { id: 1, name: "Apollo Blood Bank", location: "Hyderabad", available: true },
    { id: 2, name: "Red Cross Blood Center", location: "Vijayawada", available: false },
    { id: 3, name: "Care Hospitals Blood Bank", location: "Visakhapatnam", available: true },
    { id: 4, name: "NIMS Blood Bank", location: "Guntur", available: false },
    { id: 5, name: "Medico Blood Center", location: "Tirupati", available: true },
  ]);

  return (
    <div className="bloodbank-container">
      <h2>Available Blood Banks</h2>
      <div className="bloodbank-list">
        {centers.map((center) => (
          <div
            key={center.id}
            className={`bloodbank-card ${center.available ? "available" : "not-available"}`}
          >
            <h3>{center.name}</h3>
            <p>{center.location}</p>
            <span className="status">
              {center.available ? "✅ Available" : "❌ Not Available"}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
};

export default BloodBankPage;
